async function main() {
  const env = loadEnv();
  const supabase = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.SUPABASE_SERVICE_ROLE_KEY, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  const { data: sw, error: swErr } = await supabase.from('software').select('id, slug');
  if (swErr) throw new Error(swErr.message);
  const idBySlug = Object.fromEntries(sw.map(s => [s.slug, s.id]));

  const { data: existingArticles, error: exErr } = await supabase.from('articles').select('id, slug');
  if (exErr) throw new Error(exErr.message);
  const existingBySlug = Object.fromEntries(existingArticles.map(a => [a.slug, a.id]));

  console.log(`Existing articles in DB: ${existingArticles.length} (kept, appending/updating on top).\n`);

  let inserted = 0;
  let updated = 0;

  for (const a of ARTICLES) {
    const words = wordCount(a.content);
    const flag = words < 3000 ? '  <<< BELOW 3000 WORDS' : '';
    console.log(`${a.slug}: ${words} words${flag}`);

    const author = AUTHORS[a.author];
    const relatedId = a.related_software_slug ? (idBySlug[a.related_software_slug] ?? null) : null;

    const row = {
      title: a.title,
      slug: a.slug,
      excerpt: a.excerpt,
      content: a.content,
      category_tag: a.category_tag,
      related_software_id: relatedId,
      author_name: author.author_name,
      author_title: author.author_title,
      author_bio: author.author_bio,
      meta_title: a.meta_title,
      meta_description: a.meta_description,
      read_time_minutes: Math.max(4, Math.round(words / 200)),
      status: 'published',
      featured: !!a.featured,
      published_date: a.published_date,
    };

    if (existingBySlug[a.slug]) {
      const { error } = await supabase.from('articles').update(row).eq('id', existingBySlug[a.slug]);
      if (error) throw new Error(`Update failed for ${a.slug}: ${error.message}`);
      updated++;
    } else {
      const { error } = await supabase.from('articles').insert(row);
      if (error) throw new Error(`Insert failed for ${a.slug}: ${error.message}`);
      inserted++;
    }
  }

  console.log(`\nInserted ${inserted}, updated ${updated}.`);
  const { count } = await supabase.from('articles').select('id', { count: 'exact', head: true });
  console.log(`Total articles in DB now: ${count}`);
}

main().catch(err => { console.error(err.message || err); process.exit(1); });
